INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_032', 'seed_recipe_006', 0, 'Cream butter + sugars — Paddle attachment, medium speed, 2–3 minutes until just fluffy — not airy.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_033', 'seed_recipe_006', 1, 'Add eggs one at a time — Mix until smooth after each addition. Add vanilla.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_034', 'seed_recipe_006', 2, 'Combine dry ingredients in a separate bowl, then add to mixer in two additions on low speed.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_035', 'seed_recipe_006', 3, 'Fold in chocolate by hand to avoid overmixing.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_036', 'seed_recipe_006', 4, 'Portion dough — Scoop 140g dough balls. Tear and press together lightly for craggy tops.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_037', 'seed_recipe_006', 5, 'Chill — Minimum 2 hours, ideally 4+ hours or overnight. Dough should feel firm throughout.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_038', 'seed_recipe_006', 6, 'Bake — 400°F / 205°C, 13–14 minutes. Edges golden, centers still soft.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_039', 'seed_recipe_006', 7, 'Cool on tray 10–15 minutes before moving.');
