INSERT INTO "Recipe" (id, userId, title, servings, prepTimeMinutes, cookTimeMinutes, totalTimeMinutes, createdAt, updatedAt) VALUES ('seed_recipe_007', 'seed_user_001', 'Salted Chocolate Chip Cookies', 24, 20, 12, 45, datetime('now'), datetime('now'));
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_040', 'seed_recipe_007', 0, 'Once your butter has cooled, add sugars and stir well.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_041', 'seed_recipe_007', 1, 'Add eggs and vanilla extract and stir until dough is uniform.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_042', 'seed_recipe_007', 2, 'In a separate, medium-sized bowl, whisk together flour, cornstarch, baking powder, baking soda and salt.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_043', 'seed_recipe_007', 3, 'Gradually add the flour mixture to butter mixture, stirring until ingredients are completely combined.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_044', 'seed_recipe_007', 4, 'Add chocolate and stir well so that chocolate is well distributed through the batter.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_045', 'seed_recipe_007', 5, 'Cover cookie dough bowl with plastic wrap and chill in the refrigerator for at least 30 minutes.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_046', 'seed_recipe_007', 6, 'About 15 minutes before dough has finished chilling, preheat oven to 350°F (175°C) and line cookie sheets with parchment paper.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_047', 'seed_recipe_007', 7, 'Once dough has finished chilling, scoop by about 2 Tablespoon-sized portions. Gently roll the dough between your palms into a round ball, then place at least 2" apart on prepared cookie sheet.');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_048', 'seed_recipe_007', 8, 'Bake at 350°F (175°C) for 10–12 minutes or until edges are just beginning to turn golden (cookies should still be quite soft and may appear slightly underbaked in center).');
INSERT INTO "RecipeInstruction" (id, recipeId, sortOrder, text) VALUES ('seed_instr_049', 'seed_recipe_007', 9, 'Let cookies cool about a minute, then sprinkle lightly with flaky sea salt. Allow to cool completely on baking sheet before removing.');
